UPDATE pi_schedules
SET SCHEDULE_STATUS = #{statusYn}
WHERE SCHEDULE_ID = #{scheduleId}

UPDATE pi_schedules
SET SCHEDULE_NEXT_SCAN = UNIX_TIMESTAMP(NOW())
WHERE SCHEDULE_ID = #{scheduleId}

mapper.select:
SELECT sh.TARGET_ID AS targetId, t.NAME AS targetName, IFNULL(a.AGENT_CONNECTED_IP, '') AS targetIp, sh.STATUS AS scanStatus, sh.STARTED AS startDt, sh.REGDATE AS regDt FROM pi_scan_history sh LEFT JOIN pi_targets t ON sh.TARGET_ID = t.TARGET_ID AND sh.AP_NO = t.AP_NO LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO
AND sh.TARGET_ID = #{targetId}
ORDER BY sh.REGDATE DESC, sh.STARTED DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM pi_scan_history


        AND TARGET_ID = #{targetId}

SELECT s.SCHEDULE_ID, s.SCHEDULE_LABEL AS SCHEDULE_NAME, s.SCHEDULE_REPEAT_DAYS AS SCHEDULE_TYPE, s.SCHEDULE_DATATYPE_PROFILES AS CRON_EXPRESSION, NULL AS POLICY_ID, s.SCHEDULE_TARGET_ID AS TARGET_GROUP_ID, s.SCHEDULE_STATUS AS STATUS_YN, s.SCHEDULE_TARGET_NAME AS DESCRIPTION, NULL AS LAST_RUN_DT, s.SCHEDULE_NEXT_SCAN AS NEXT_RUN_DT, s.REGDATE AS REG_DT, NULL AS REG_USER, NULL AS MOD_DT, d.DATATYPE_LABEL AS POLICY_NAME FROM pi_schedules s LEFT JOIN pi_datatypes d ON d.DATATYPE_ID = s.SCHEDULE_DATATYPE_PROFILES
AND (s.SCHEDULE_LABEL LIKE CONCAT('%', #{hostName}, '%') OR s.SCHEDULE_TARGET_NAME LIKE CONCAT('%', #{hostName}, '%') OR s.SCHEDULE_TARGET_ID LIKE CONCAT('%', #{hostName}, '%'))
AND s.SCHEDULE_STATUS = #{status}
ORDER BY s.REGDATE DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM pi_schedules s
AND (s.SCHEDULE_LABEL LIKE CONCAT('%', #{hostName}, '%') OR s.SCHEDULE_TARGET_NAME LIKE CONCAT('%', #{hostName}, '%') OR s.SCHEDULE_TARGET_ID LIKE CONCAT('%', #{hostName}, '%'))
AND s.SCHEDULE_STATUS = #{status}

SELECT sh.TARGET_ID AS targetId, t.NAME AS targetName, IFNULL(a.AGENT_CONNECTED_IP, '') AS targetIp, sh.STATUS AS scanStatus, sh.STARTED AS startDt, sh.REGDATE AS regDt FROM pi_scan_history sh LEFT JOIN pi_targets t ON sh.TARGET_ID = t.TARGET_ID AND sh.AP_NO = t.AP_NO LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO
AND sh.TARGET_ID = #{targetId}
AND (t.NAME LIKE CONCAT('%', #{hostName}, '%') OR a.AGENT_CONNECTED_IP LIKE CONCAT('%', #{hostName}, '%'))
AND sh.STATUS = #{status}
ORDER BY sh.REGDATE DESC, sh.STARTED DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM pi_scan_history sh
LEFT JOIN pi_targets t ON sh.TARGET_ID = t.TARGET_ID AND sh.AP_NO = t.AP_NO LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO
AND sh.TARGET_ID = #{targetId}
AND (t.NAME LIKE CONCAT('%', #{hostName}, '%') OR a.AGENT_CONNECTED_IP LIKE CONCAT('%', #{hostName}, '%'))
AND sh.STATUS = #{status}

